const INDUSTRIES_FLAT = [];
INDUSTRY_TREE.forEach(gang => {
  gang.目.forEach(mu => {
    INDUSTRIES_FLAT.push({ ...mu, 纲_id: gang.id, 纲_name: gang.纲, 纲_desc: gang.纲_desc });
  });
});

const MAJOR_MAP = Object.fromEntries(MAJORS.map(m => [m.id, m]));
const UNI_MAP   = Object.fromEntries(UNIVERSITIES.map(u => [u.id, u]));
const CITY_MAP  = Object.fromEntries(CITIES.map(c => [c.id, c]));
const IND_MAP   = Object.fromEntries(INDUSTRIES_FLAT.map(i => [i.id, i]));

function buildSearchIndex() {
  const index = [];
  MAJORS.forEach(m => {
    index.push({ keyword: m.name, type: "major", id: m.id, entity: m });
    if (m.category) index.push({ keyword: m.category, type: "major", id: m.id, entity: m });
    (m.tags || []).forEach(t => index.push({ keyword: t, type: "major", id: m.id, entity: m }));
  });
  UNIVERSITIES.forEach(u => {
    index.push({ keyword: u.name, type: "university", id: u.id, entity: u });
    if (u.shortName) index.push({ keyword: u.shortName, type: "university", id: u.id, entity: u });
    (u.feature_tags || []).forEach(t => index.push({ keyword: t, type: "university", id: u.id, entity: u }));
  });
  CITIES.forEach(c => {
    index.push({ keyword: c.name, type: "city", id: c.id, entity: c });
    index.push({ keyword: c.region, type: "city", id: c.id, entity: c });
  });
  INDUSTRIES_FLAT.forEach(ind => {
    index.push({ keyword: ind.name, type: "industry", id: ind.id, entity: ind });
    index.push({ keyword: ind.纲_name, type: "industry", id: ind.id, entity: ind });
  });
  return index;
}

const SEARCH_INDEX = buildSearchIndex();
